document.addEventListener("alpine:init",()=>{Alpine.data("vetcare",()=>({menuOpen:!1,scrolled:!1,faqOpen:null,demoEmail:"",demoDone:!1,demoErr:!1,waitEmail:"",waitDone:!1,waitErr:!1,contactName:"",contactEmail:"",contactMessage:"",contactHoney:"",contactDone:!1,contactErr:"",init(){window.addEventListener("scroll",()=>{this.scrolled=window.scrollY>12},{passive:!0})},isEmailValid(t){return/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test((t||"").trim())},submitDemo(t){if(t.preventDefault(),!this.isEmailValid(this.demoEmail)){this.demoErr=!0;return}this.demoErr=!1,this.demoDone=!0},submitWait(t){if(t.preventDefault(),!this.isEmailValid(this.waitEmail)){this.waitErr=!0;return}this.waitErr=!1,this.waitDone=!0},submitContact(t){if(t.preventDefault(),this.contactHoney.trim()){this.contactDone=!0;return}if(!this.isEmailValid(this.contactEmail)){this.contactErr="\u041C\u043E\u043B\u044F, \u0432\u044A\u0432\u0435\u0434\u0435\u0442\u0435 \u0432\u0430\u043B\u0438\u0434\u0435\u043D \u0438\u043C\u0435\u0439\u043B \u0430\u0434\u0440\u0435\u0441.";return}if(!this.contactMessage.trim()){this.contactErr="\u041C\u043E\u043B\u044F, \u043D\u0430\u043F\u0438\u0448\u0435\u0442\u0435 \u0441\u044A\u043E\u0431\u0449\u0435\u043D\u0438\u0435.";return}this.contactErr="",this.contactDone=!0}}))});
